const input = $input.first().json;
const action = input.action || 'generate_image';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const BRIDGE_URL = 'http://file-bridge:3200';
const GEMINI_BASE = 'https://generativelanguage.googleapis.com/v1beta';
const IMAGE_MODEL = 'gemini-3-pro-image-preview';
const VIDEO_MODEL = 'veo-3.1-generate-preview';
const POLL_INTERVAL_MS = 5000;
const POLL_MAX_ATTEMPTS = 5;

const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

// Fetch API key
const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.google-media-gen&cred_key=eq.gemini_api_key&select=cred_value',
  headers: pgHeaders
});
if (!creds || !creds[0] || !creds[0].cred_value) {
  return [{ json: { error: 'Gemini API key not configured. Use add_credential to set google-media-gen / gemini_api_key.' } }];
}
const apiKey = creds[0].cred_value;

// === Helpers ===
async function storeBytesInBridge(bytes, fileName, mimeType) {
  const b64 = Buffer.from(bytes).toString('base64');
  const stored = await helpers.httpRequest({
    method: 'POST',
    url: BRIDGE_URL + '/upload/base64',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ content_base64: b64, file_name: fileName, mime_type: mimeType })
  });
  return stored;
}

async function fetchFileRefAsBase64(fileRef) {
  const meta = await helpers.httpRequest({
    method: 'GET',
    url: BRIDGE_URL + '/files/' + fileRef + '/meta'
  });
  const dl = await helpers.httpRequest({
    method: 'GET',
    url: BRIDGE_URL + '/files/' + fileRef,
    encoding: 'arraybuffer',
    returnFullResponse: true
  });
  const b64 = Buffer.from(dl.body).toString('base64');
  return { base64: b64, mime_type: meta.mime_type || 'application/octet-stream', file_name: meta.file_name };
}

function successFileResult(name, sizeStr, storedId) {
  return 'File ready: ' + name + ' (' + sizeStr + ')\n[send_file: ' + BRIDGE_URL + '/files/' + storedId + ']';
}

function fmtSize(bytes) {
  if (!bytes) return 'unknown size';
  if (bytes < 1024) return bytes + ' B';
  if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
  return (bytes / 1024 / 1024).toFixed(2) + ' MB';
}

async function geminiPost(url, body) {
  const resp = await helpers.httpRequest({
    method: 'POST',
    url: url,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
    json: false
  });
  if (resp.statusCode >= 400) {
    const errBody = typeof resp.body === 'string' ? resp.body : JSON.stringify(resp.body);
    throw new Error('HTTP ' + resp.statusCode + ': ' + errBody.substring(0, 500));
  }
  return typeof resp.body === 'string' ? JSON.parse(resp.body) : resp.body;
}

async function geminiGet(url) {
  const resp = await helpers.httpRequest({
    method: 'GET',
    url: url,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
    json: false
  });
  if (resp.statusCode >= 400) {
    const errBody = typeof resp.body === 'string' ? resp.body : JSON.stringify(resp.body);
    throw new Error('HTTP ' + resp.statusCode + ': ' + errBody.substring(0, 500));
  }
  return typeof resp.body === 'string' ? JSON.parse(resp.body) : resp.body;
}

async function downloadAndStoreVideo(op) {
  const samples = op && op.response && op.response.generateVideoResponse && op.response.generateVideoResponse.generatedSamples;
  if (!samples || !samples[0] || !samples[0].video || !samples[0].video.uri) {
    throw new Error('Operation done but no video URI found. Raw: ' + JSON.stringify(op).slice(0, 500));
  }
  const videoUri = samples[0].video.uri;
  const sep = videoUri.indexOf('?') >= 0 ? '&' : '?';
  const dlUrl = videoUri + sep + 'key=' + encodeURIComponent(apiKey);

  const dl = await helpers.httpRequest({
    method: 'GET',
    url: dlUrl,
    encoding: 'arraybuffer',
    returnFullResponse: true
  });

  const stored = await storeBytesInBridge(dl.body, 'veo_' + Date.now() + '.mp4', 'video/mp4');
  return stored;
}

// === Actions ===
if (action === 'generate_image') {
  const prompt = input.prompt;
  if (!prompt) return [{ json: { error: 'Parameter "prompt" is required.' } }];

  const aspect = input.aspect_ratio || '1:1';
  const body = {
    contents: [{ role: 'user', parts: [{ text: prompt }] }],
    generationConfig: {
      responseModalities: ['IMAGE'],
      imageConfig: { aspectRatio: aspect }
    }
  };

  try {
    const resp = await geminiPost(
      GEMINI_BASE + '/models/' + IMAGE_MODEL + ':generateContent?key=' + encodeURIComponent(apiKey),
      body
    );
    const parts = (resp.candidates && resp.candidates[0] && resp.candidates[0].content && resp.candidates[0].content.parts) || [];
    const imgPart = parts.find(p => p.inlineData && p.inlineData.data);
    if (!imgPart) {
      return [{ json: { error: 'No image returned. Raw response: ' + JSON.stringify(resp).slice(0, 500) } }];
    }
    const bytes = Buffer.from(imgPart.inlineData.data, 'base64');
    const stored = await storeBytesInBridge(bytes, 'nanobanana_' + Date.now() + '.png', imgPart.inlineData.mimeType || 'image/png');
    return [{ json: { result: successFileResult(stored.file_name, fmtSize(stored.size_bytes), stored.id) } }];
  } catch (e) {
    return [{ json: { error: 'generate_image failed: ' + e.message } }];
  }

} else if (action === 'edit_image') {
  const prompt = input.prompt;
  const fileRef = input.file_ref;
  if (!prompt) return [{ json: { error: 'Parameter "prompt" is required.' } }];
  if (!fileRef) return [{ json: { error: 'Parameter "file_ref" is required (file-bridge id of the source image).' } }];

  const aspect = input.aspect_ratio || null;

  try {
    const src = await fetchFileRefAsBase64(fileRef);
    const body = {
      contents: [{
        role: 'user',
        parts: [
          { text: prompt },
          { inline_data: { mime_type: src.mime_type, data: src.base64 } }
        ]
      }],
      generationConfig: { responseModalities: ['IMAGE'] }
    };
    if (aspect) body.generationConfig.imageConfig = { aspectRatio: aspect };

    const resp = await geminiPost(
      GEMINI_BASE + '/models/' + IMAGE_MODEL + ':generateContent?key=' + encodeURIComponent(apiKey),
      body
    );
    const parts = (resp.candidates && resp.candidates[0] && resp.candidates[0].content && resp.candidates[0].content.parts) || [];
    const imgPart = parts.find(p => p.inlineData && p.inlineData.data);
    if (!imgPart) {
      return [{ json: { error: 'No image returned. Raw response: ' + JSON.stringify(resp).slice(0, 500) } }];
    }
    const bytes = Buffer.from(imgPart.inlineData.data, 'base64');
    const stored = await storeBytesInBridge(bytes, 'nanobanana_edit_' + Date.now() + '.png', imgPart.inlineData.mimeType || 'image/png');
    return [{ json: { result: successFileResult(stored.file_name, fmtSize(stored.size_bytes), stored.id) } }];
  } catch (e) {
    return [{ json: { error: 'edit_image failed: ' + e.message } }];
  }

} else if (action === 'generate_video') {
  const prompt = input.prompt;
  if (!prompt) return [{ json: { error: 'Parameter "prompt" is required.' } }];

  const aspect = input.aspect_ratio || '16:9';
  const negative = input.negative_prompt || '';
  const duration = parseInt(input.duration_seconds) || 8;

  const params = { aspectRatio: aspect, durationSeconds: duration };
  if (negative) params.negativePrompt = negative;

  try {
    const startResp = await geminiPost(
      GEMINI_BASE + '/models/' + VIDEO_MODEL + ':predictLongRunning?key=' + encodeURIComponent(apiKey),
      { instances: [{ prompt: prompt }], parameters: params }
    );
    const opName = startResp.name;
    if (!opName) {
      return [{ json: { error: 'Veo did not return an operation name. Raw: ' + JSON.stringify(startResp).slice(0, 500) } }];
    }

    return [{ json: { result: 'Video generation started. operation_id: ' + opName + '\nNow call wait_for_video with this operation_id REPEATEDLY (in this same conversation turn) until it returns the finished MP4 file. Each wait_for_video call waits up to 25 seconds; typical Veo 3.1 jobs need 2-8 such calls.' } }];
  } catch (e) {
    return [{ json: { error: 'generate_video failed: ' + e.message } }];
  }

} else if (action === 'wait_for_video') {
  const opId = input.operation_id;
  if (!opId) return [{ json: { error: 'Parameter "operation_id" is required.' } }];

  try {
    let op = await geminiGet(GEMINI_BASE + '/' + opId + '?key=' + encodeURIComponent(apiKey));
    let attempts = 0;
    while (!op.done && attempts < POLL_MAX_ATTEMPTS) {
      await new Promise(r => setTimeout(r, POLL_INTERVAL_MS));
      op = await geminiGet(GEMINI_BASE + '/' + opId + '?key=' + encodeURIComponent(apiKey));
      attempts++;
    }
    if (!op.done) {
      return [{ json: { result: 'Video still generating. Call wait_for_video AGAIN with the SAME operation_id: ' + opId } }];
    }
    if (op.error) {
      return [{ json: { error: 'Veo operation failed: ' + (op.error.message || JSON.stringify(op.error)) } }];
    }
    const stored = await downloadAndStoreVideo(op);
    return [{ json: { result: successFileResult(stored.file_name, fmtSize(stored.size_bytes), stored.id) } }];
  } catch (e) {
    return [{ json: { error: 'wait_for_video failed: ' + e.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Available: generate_image, edit_image, generate_video, wait_for_video.' } }];
}
